 3→export async function resolveIdentity(input: {
 4→  surreal: Surreal;
 5→  provider: string;
 6→  providerId: string;
 7→  workspaceRecord: RecordId<"workspace", string>;
 8→}): Promise<RecordId<"person", string> | undefined> {
 9→  const [rows] = await input.surreal.query<[Array<{ id: RecordId<"person", string> }>]>(
10→    `SELECT id FROM person
11→     WHERE id IN (SELECT VALUE \`in\` FROM member_of WHERE out = $workspace)
12→       AND identities[WHERE provider = $provider AND id = $providerId]
13→     LIMIT 1;`,
14→    {
15→      workspace: input.workspaceRecord,
16→      provider: input.provider,
17→      providerId: input.providerId,
18→    },
19→  );
20→
21→  return rows.length > 0 ? rows[0].id : undefined;
22→}
