  1→import type { ToolExecutionOptions } from "ai";
  2→import { RecordId, type Surreal } from "surrealdb";
  3→import type { AgentType, ChatToolExecutionContext } from "../chat/tools/types";
  4→import { requireToolContext } from "../chat/tools/helpers";
  5→import { jsonError } from "../http/response";
  6→
  7→export type AuthorityAction =
  8→  | "create_decision"
  9→  | "confirm_decision"
 10→  | "create_task"
 11→  | "complete_task"
 12→  | "create_observation"
 13→  | "acknowledge_observation"
 14→  | "resolve_observation"
 15→  | "create_question"
 16→  | "create_suggestion";
 17→
 18→export type AuthorityPermission = "auto" | "provisional" | "propose" | "blocked";
 19→
 20→export type AuthorizedContext = {
 21→  context: ChatToolExecutionContext;
 22→  permission: AuthorityPermission;
 23→};
 24→
 25→export class AuthorityError extends Error {
 26→  constructor(
 27→    public readonly permission: "propose" | "blocked",
 28→    public readonly action: AuthorityAction,
 29→    public readonly agentType: AgentType,
 30→  ) {
 31→    const verb = permission === "blocked" ? "not authorized" : "can only propose";
 32→    super(`${agentType} is ${verb} for action: ${action}`);
 33→    this.name = "AuthorityError";
 34→  }
 35→}
 36→
 37→const ACTOR_DEFAULT_AGENT_TYPE: Partial<Record<string, AgentType>> = {
 38→  pm_agent: "management",
 39→  analytics_agent: "observer",
 40→};
 41→
 42→export async function checkAuthority(input: {
 43→  surreal: Surreal;
 44→  agentType: AgentType;
 45→  action: AuthorityAction;
 46→  workspaceRecord?: RecordId<"workspace", string>;
 47→}): Promise<AuthorityPermission> {
 48→  // 1. Try workspace-specific override
 49→  if (input.workspaceRecord) {
 50→    const [wsRows] = await input.surreal.query<[Array<{ permission: string }>]>(
 51→      "SELECT permission FROM authority_scope WHERE agent_type = $agentType AND action = $action AND workspace = $workspace LIMIT 1;",
 52→      {
 53→        agentType: input.agentType,
 54→        action: input.action,
 55→        workspace: input.workspaceRecord,
 56→      },
 57→    );
 58→
 59→    if (wsRows.length > 0) {
 60→      return wsRows[0].permission as AuthorityPermission;
 61→    }
 62→  }
 63→
 64→  // 2. Fall back to global default (workspace IS NONE)
 65→  const [globalRows] = await input.surreal.query<[Array<{ permission: string }>]>(
 66→    "SELECT permission FROM authority_scope WHERE agent_type = $agentType AND action = $action AND workspace IS NONE LIMIT 1;",
 67→    { agentType: input.agentType, action: input.action },
 68→  );
 69→
 70→  if (globalRows.length > 0) {
 71→    return globalRows[0].permission as AuthorityPermission;
 72→  }
 73→
 74→  // 3. Fail-safe: no row = blocked
 75→  return "blocked";
 76→}
 77→
 78→export async function requireAuthorizedContext(
 79→  options: ToolExecutionOptions,
 80→  action: AuthorityAction,
 81→  deps: { surreal: Surreal },
 82→): Promise<AuthorizedContext> {
 83→  const context = requireToolContext(options);
 84→
 85→  // Contract: MCP contexts must never claim human presence
 86→  if (context.humanPresent && context.actor === "mcp") {
 87→    throw new Error("Contract violation: humanPresent must not be true for MCP contexts");
 88→  }
 89→
 90→  // Human-present web sessions bypass authority (human IS the authority)
 91→  if (context.humanPresent) {
 92→    return { context, permission: "auto" };
 93→  }
 94→
 95→  const agentType: AgentType =
 96→    context.agentType ?? ACTOR_DEFAULT_AGENT_TYPE[context.actor] ?? "code_agent";
 97→
 98→  const permission = await checkAuthority({
 99→    surreal: deps.surreal,
100→    agentType,
101→    action,
102→    workspaceRecord: context.workspaceRecord,
103→  });
104→
105→  if (permission === "blocked") {
106→    throw new AuthorityError("blocked", action, agentType);
107→  }
108→
109→  if (permission === "propose") {
110→    throw new AuthorityError("propose", action, agentType);
111→  }
112→
113→  // "auto" or "provisional" — caller proceeds (may mark output as provisional)
114→  return { context, permission };
115→}
116→
117→export function checkAuthorityOrError(
118→  permission: AuthorityPermission,
119→  action: AuthorityAction,
120→  agentType: AgentType,
121→): Response | undefined {
122→  if (permission === "blocked") {
123→    return jsonError(`${agentType} is not authorized for action: ${action}`, 403);
124→  }
125→  if (permission === "propose") {
126→    return jsonError(
127→      `${agentType} can only propose ${action} — requires human approval`,
128→      403,
129→    );
130→  }
131→  return undefined;
132→}
133→

  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { jsonError } from "../http/response";
  3→import type { AgentType } from "../chat/tools/types";
  4→import { createJwtValidator, type BrainTokenClaims } from "./token-validation";
  5→import type { McpAuthResult } from "./types";
  6→
  7→type WorkspaceRow = {
  8→  id: RecordId<"workspace", string>;
  9→  name: string;
 10→};
 11→
 12→const VALID_AGENT_TYPES = new Set<AgentType>([
 13→  "code_agent", "architect", "management", "design_partner", "observer",
 14→]);
 15→
 16→let validateToken: ((token: string) => Promise<BrainTokenClaims>) | undefined;
 17→
 18→/**
 19→ * Authenticate an MCP request via OAuth 2.1 JWT Bearer token.
 20→ * Validates the JWT signature via JWKS, extracts claims, and verifies workspace access.
 21→ * Returns auth context on success, or an error Response.
 22→ */
 23→export async function authenticateMcpRequest(
 24→  request: Request,
 25→  workspaceId: string,
 26→  surreal: Surreal,
 27→  issuerUrl: string,
 28→): Promise<McpAuthResult | Response> {
 29→  const authHeader = request.headers.get("authorization");
 30→  if (!authHeader || !authHeader.startsWith("Bearer ")) {
 31→    return jsonError("missing or invalid Authorization header", 401);
 32→  }
 33→
 34→  const token = authHeader.slice(7);
 35→  if (!token) {
 36→    return jsonError("empty Bearer token", 401);
 37→  }
 38→
 39→  // Lazily initialize the JWT validator
 40→  if (!validateToken) {
 41→    validateToken = createJwtValidator(issuerUrl);
 42→  }
 43→
 44→  let claims: BrainTokenClaims;
 45→  try {
 46→    claims = await validateToken(token);
 47→  } catch (err) {
 48→    const detail = err instanceof Error ? err.message : String(err);
 49→    console.error(`[MCP Auth] JWT validation failed: ${detail}`);
 50→    return jsonError("invalid or expired token", 401);
 51→  }
 52→
 53→  // Extract person identity from sub claim
 54→  const personId = claims.sub;
 55→  if (!personId) {
 56→    return jsonError("token missing sub claim", 401);
 57→  }
 58→
 59→  // Extract workspace from custom claim or verify against requested workspace
 60→  const claimedWorkspace = claims["urn:brain:workspace"];
 61→  if (claimedWorkspace && claimedWorkspace !== workspaceId) {
 62→    return jsonError("token workspace does not match requested workspace", 403);
 63→  }
 64→
 65→  // Verify workspace exists
 66→  const workspaceRecord = new RecordId("workspace", workspaceId);
 67→  const workspace = await surreal.select<WorkspaceRow>(workspaceRecord);
 68→  if (!workspace) {
 69→    return jsonError("workspace not found", 404);
 70→  }
 71→
 72→  // If no workspace claim in token, verify membership via DB
 73→  if (!claimedWorkspace) {
 74→    const [memberRows] = await surreal.query<[Array<{ role: string }>]>(
 75→      `SELECT role FROM member_of WHERE in = $person AND out = $ws LIMIT 1;`,
 76→      { person: new RecordId("person", personId), ws: workspaceRecord },
 77→    );
 78→    if (!memberRows || memberRows.length === 0) {
 79→      return jsonError("token owner is not a member of this workspace", 403);
 80→    }
 81→  }
 82→
 83→  // Extract scopes from token
 84→  const scopeString = claims.scope ?? "";
 85→  const scopes = new Set(scopeString.split(" ").filter(Boolean));
 86→
 87→  // Agent type from header or from token claim
 88→  const claimedAgentType = claims["urn:brain:agent_type"];
 89→  const rawAgentType = request.headers.get("x-agent-type") ?? claimedAgentType ?? "code_agent";
 90→  if (!VALID_AGENT_TYPES.has(rawAgentType as AgentType)) {
 91→    return jsonError(`invalid agent type: ${rawAgentType}`, 400);
 92→  }
 93→
 94→  return {
 95→    workspaceRecord,
 96→    workspaceName: workspace.name,
 97→    agentType: rawAgentType as AgentType,
 98→    personRecord: new RecordId("person", personId),
 99→    scopes,
100→    humanPresent: false as const,
101→  };
102→}
103→

