  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { resolveByEmail } from "../iam/identity";
  3→import type { PersistableExtractableEntityKind } from "./types";
  4→
  5→export type PersonAttributionPatch =
  6→  | { kind: "feature"; field: "owner"; value: string }
  7→  | { kind: "feature"; field: "owner_name"; value: string }
  8→  | { kind: "task"; field: "owner"; value: string }
  9→  | { kind: "task"; field: "owner_name"; value: string }
 10→  | { kind: "decision"; field: "decided_by"; value: string }
 11→  | { kind: "decision"; field: "decided_by_name"; value: string }
 12→  | { kind: "question"; field: "assigned_to"; value: string }
 13→  | { kind: "question"; field: "assigned_to_name"; value: string };
 14→
 15→export async function findWorkspacePersonByName(input: {
 16→  surreal: Surreal;
 17→  workspaceRecord: RecordId<"workspace", string>;
 18→  personName: string;
 19→}): Promise<RecordId<"person", string> | undefined> {
 20→  const normalizedName = input.personName.trim();
 21→  if (normalizedName.length === 0) {
 22→    return undefined;
 23→  }
 24→
 25→  const [rows] = await input.surreal
 26→    .query<[Array<{ id: RecordId<"person", string> }>]>(
 27→      [
 28→        "SELECT id",
 29→        "FROM person",
 30→        "WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace)",
 31→        "AND string::lowercase(name) = string::lowercase($name)",
 32→        "LIMIT 1;",
 33→      ].join(" "),
 34→      {
 35→        workspace: input.workspaceRecord,
 36→        name: normalizedName,
 37→      },
 38→    )
 39→    .collect<[Array<{ id: RecordId<"person", string> }>]>() ;
 40→
 41→  return rows[0]?.id;
 42→}
 43→
 44→/**
 45→ * Composite resolver: exact name match → email match (if input looks like an email).
 46→ */
 47→export async function resolveWorkspacePerson(input: {
 48→  surreal: Surreal;
 49→  workspaceRecord: RecordId<"workspace", string>;
 50→  personName: string;
 51→}): Promise<RecordId<"person", string> | undefined> {
 52→  const byName = await findWorkspacePersonByName(input);
 53→  if (byName) return byName;
 54→
 55→  if (input.personName.includes("@")) {
 56→    return resolveByEmail({
 57→      surreal: input.surreal,
 58→      email: input.personName,
 59→      workspaceRecord: input.workspaceRecord,
 60→    });
