24→export async function resolveByEmail(input: {
25→  surreal: Surreal;
26→  email: string;
27→  workspaceRecord: RecordId<"workspace", string>;
28→}): Promise<RecordId<"person", string> | undefined> {
29→  const normalizedEmail = input.email.trim().toLowerCase();
30→  if (normalizedEmail.length === 0) return undefined;
31→
32→  const [rows] = await input.surreal.query<[Array<{ id: RecordId<"person", string> }>]>(
33→    `SELECT id FROM person
34→     WHERE id IN (SELECT VALUE \`in\` FROM member_of WHERE out = $workspace)
35→       AND string::lowercase(contact_email) = $email
36→     LIMIT 1;`,
37→    {
