  1→import type { ToolExecutionOptions } from "ai";
  2→import { RecordId, type Surreal } from "surrealdb";
  3→import type { AgentType, ChatToolExecutionContext } from "../chat/tools/types";
  4→import { requireToolContext } from "../chat/tools/helpers";
  5→import { jsonError } from "../http/response";
  6→
  7→export type AuthorityAction =
  8→  | "create_decision"
  9→  | "confirm_decision"
 10→  | "create_task"
 11→  | "complete_task"
 12→  | "create_observation"
 13→  | "acknowledge_observation"
 14→  | "resolve_observation"
 15→  | "create_question"
 16→  | "create_suggestion";
 17→
 18→export type AuthorityPermission = "auto" | "provisional" | "propose" | "blocked";
 19→
 20→export type AuthorizedContext = {
 21→  context: ChatToolExecutionContext;
 22→  permission: AuthorityPermission;
 23→};
 24→
 25→export class AuthorityError extends Error {
 26→  constructor(
 27→    public readonly permission: "propose" | "blocked",
 28→    public readonly action: AuthorityAction,
 29→    public readonly agentType: AgentType,
 30→  ) {
 31→    const verb = permission === "blocked" ? "not authorized" : "can only propose";
 32→    super(`${agentType} is ${verb} for action: ${action}`);
 33→    this.name = "AuthorityError";
 34→  }
 35→}
 36→
 37→const ACTOR_DEFAULT_AGENT_TYPE: Partial<Record<string, AgentType>> = {
 38→  pm_agent: "management",
 39→  analytics_agent: "observer",
 40→};
 41→
 42→export async function checkAuthority(input: {
 43→  surreal: Surreal;
 44→  agentType: AgentType;
 45→  action: AuthorityAction;
 46→  workspaceRecord?: RecordId<"workspace", string>;
 47→}): Promise<AuthorityPermission> {
 48→  // 1. Try workspace-specific override
 49→  if (input.workspaceRecord) {
 50→    const [wsRows] = await input.surreal.query<[Array<{ permission: string }>]>(
 51→      "SELECT permission FROM authority_scope WHERE agent_type = $agentType AND action = $action AND workspace = $workspace LIMIT 1;",
 52→      {
 53→        agentType: input.agentType,
 54→        action: input.action,
 55→        workspace: input.workspaceRecord,
 56→      },
 57→    );
 58→
 59→    if (wsRows.length > 0) {
 60→      return wsRows[0].permission as AuthorityPermission;
 61→    }
 62→  }
 63→
 64→  // 2. Fall back to global default (workspace IS NONE)
 65→  const [globalRows] = await input.surreal.query<[Array<{ permission: string }>]>(
 66→    "SELECT permission FROM authority_scope WHERE agent_type = $agentType AND action = $action AND workspace IS NONE LIMIT 1;",
 67→    { agentType: input.agentType, action: input.action },
 68→  );
 69→
 70→  if (globalRows.length > 0) {
 71→    return globalRows[0].permission as AuthorityPermission;
 72→  }
 73→
 74→  // 3. Fail-safe: no row = blocked
 75→  return "blocked";
 76→}
 77→
 78→export async function requireAuthorizedContext(
 79→  options: ToolExecutionOptions,
 80→  action: AuthorityAction,
 81→  deps: { surreal: Surreal },
 82→): Promise<AuthorizedContext> {
 83→  const context = requireToolContext(options);
 84→
 85→  // Contract: MCP contexts must never claim human presence
 86→  if (context.humanPresent && context.actor === "mcp") {
 87→    throw new Error("Contract violation: humanPresent must not be true for MCP contexts");
 88→  }
 89→
 90→  // Human-present web sessions bypass authority (human IS the authority)
 91→  if (context.humanPresent) {
 92→    return { context, permission: "auto" };
 93→  }
 94→
 95→  const agentType: AgentType =
 96→    context.agentType ?? ACTOR_DEFAULT_AGENT_TYPE[context.actor] ?? "code_agent";
 97→
 98→  const permission = await checkAuthority({
 99→    surreal: deps.surreal,
100→    agentType,
101→    action,
102→    workspaceRecord: context.workspaceRecord,
103→  });
104→
105→  if (permission === "blocked") {
106→    throw new AuthorityError("blocked", action, agentType);
107→  }
108→
109→  if (permission === "propose") {
110→    throw new AuthorityError("propose", action, agentType);
111→  }
112→
113→  // "auto" or "provisional" — caller proceeds (may mark output as provisional)
114→  return { context, permission };
115→}
116→
117→export function checkAuthorityOrError(
118→  permission: AuthorityPermission,
119→  action: AuthorityAction,
120→  agentType: AgentType,
121→): Response | undefined {
122→  if (permission === "blocked") {
123→    return jsonError(`${agentType} is not authorized for action: ${action}`, 403);
124→  }
125→  if (permission === "propose") {
126→    return jsonError(
127→      `${agentType} can only propose ${action} — requires human approval`,
128→      403,
129→    );
130→  }
131→  return undefined;
132→}
